      [
        req.user.id,
        question_id,
        question,
        category,
        transcription,
        Math.round(coaching.overall_score),
        JSON.stringify(coaching),
        transcription,
        JSON.stringify(coaching.communication),
        JSON.stringify(coaching.presentation),
